open('logs/iter_26/inspect_current.json','w').write(json.dumps(out, indent=2))
# print focused diagnostic summary
try:
    d=json.load(open('logs/iter_25/native_diag.json'))
    print(json.dumps({
      'keys': list(d.keys()),
      'before_children': d.get('before_children'),
      'before_visuals': d.get('before_visuals'),
      'has_visual_attr': d.get('has_visual_attr'),
      'trainable_return': d.get('trainable_return'),
      'after_visuals': d.get('after_visuals'),
      'error': d.get('error')
    }, indent=2)[:6000])
except Exception as e:
    print('diag_read_error', e)
